var val = Services.getValue(InitialPaymentAmnt.dataBinding);
var err = WPU.validateCurrency(val);
if( null == err )
{	var fVal = WPU.formatToTwoDP(val);
	Services.setValue(InitialPaymentAmnt.dataBinding, fVal);
}
return err;

